// ══ KITTY CONFIRM — reemplaza confirm() nativo ══
window.kittyConfirm = function(msg, onYes, onNo) {
  var old = document.getElementById('kittyConfirmModal'); if(old) old.remove();
  var backdrop = document.createElement('div');
  backdrop.id = 'kittyConfirmModal';
  backdrop.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:9999;display:flex;align-items:center;justify-content:center;padding:1.5rem;animation:fadeIn .15s ease';

  var box = document.createElement('div');
  box.style.cssText = 'background:var(--card);border-radius:24px;padding:1.6rem 1.4rem 1.2rem;max-width:300px;width:100%;box-shadow:0 12px 48px rgba(0,0,0,.25);text-align:center';

  var face = document.createElement('div');
  face.style.cssText = "font-family:'Courier New',monospace;font-size:1.3rem;color:var(--text);margin-bottom:.8rem;letter-spacing:.05em";
  face.textContent = '( ╹ -╹)?';

  var msgEl = document.createElement('div');
  msgEl.style.cssText = "font-family:var(--font-body);font-size:.85rem;font-weight:700;color:var(--text);margin-bottom:1.2rem;line-height:1.4";
  msgEl.textContent = msg;

  var btns = document.createElement('div');
  btns.style.cssText = 'display:flex;gap:.6rem;justify-content:center';

  var noBtn = document.createElement('button');
  noBtn.style.cssText = "padding:.45rem 1.2rem;border-radius:20px;border:1.5px solid var(--border);background:var(--bg);font-family:var(--font-body);font-size:.8rem;font-weight:800;color:var(--muted);cursor:pointer";
  noBtn.textContent = 'No, cancelar';
  noBtn.onclick = function(){ backdrop.remove(); if(onNo) onNo(); };

  var yesBtn = document.createElement('button');
  yesBtn.style.cssText = "padding:.45rem 1.2rem;border-radius:20px;border:none;background:var(--rosa);font-family:var(--font-body);font-size:.8rem;font-weight:800;color:#fff;cursor:pointer";
  yesBtn.textContent = 'Sí, continuar';
  yesBtn.onclick = function(){ backdrop.remove(); if(onYes) onYes(); };

  btns.appendChild(noBtn); btns.appendChild(yesBtn);
  box.appendChild(face); box.appendChild(msgEl); box.appendChild(btns);
  backdrop.appendChild(box);
  document.body.appendChild(backdrop);
  // Cerrar con Escape
  var onKey = function(e){ if(e.key==='Escape'){ backdrop.remove(); if(onNo) onNo(); document.removeEventListener('keydown',onKey); } };
  document.addEventListener('keydown', onKey);
};



// ── GLOBAL HELPERS (must load before all other scripts) ──
function dateKey(d) {
  if (typeof d === 'string') return d;
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}
function todayKey() { return dateKey(new Date()); }
